const rows = [];
for (const item of $input.all()) {
  const d = item.json || {};
  const likes = Number(d.likes) || 0;
  const comments = Number(d.num_comments) || 0;
  const followers = Number(d.followers) || 0;
  const plays = Number(d.video_play_count) || Number(d.video_play_count === "" ? 0 : d.video_play_count) || 0;
  const dur = (d.videos_duration && d.videos_duration[0] && d.videos_duration[0].video_duration) || "";
  const engRate = followers > 0 ? (likes / followers) : 0;
  // engagement score 0-100: like-rate vs followers (40) + comment volume (35) + play signal (25)
  const likeScore = Math.min(40, engRate * 400);
  const commentScore = Math.min(35, comments / 50 * 35);
  const playScore = Math.min(25, plays / 100000 * 25);
  const score = Math.round(likeScore + commentScore + playScore);
  const ts = d.date_posted ? new Date(Number(d.date_posted) * 1000).toISOString() : "";
  rows.push({ json: {
    engagement_score: score,
    engagement_rate: (engRate * 100).toFixed(2) + "%",
    user_posted: d.user_posted || "",
    followers: followers,
    likes: likes,
    num_comments: comments,
    video_play_count: plays,
    video_duration: dur,
    description: (d.description || "").slice(0, 200),
    hashtags: Array.isArray(d.hashtags) ? d.hashtags.join(" ") : (d.hashtags || ""),
    is_verified: d.is_verified ? "yes" : "no",
    is_paid_partnership: d.is_paid_partnership ? "yes" : "no",
    date_posted: ts,
    shortcode: d.shortcode || "",
    reel_url: d.url || "",
    thumbnail: d.thumbnail || "",
    profile_url: d.profile_url || "",
    posts_count: Number(d.posts_count) || 0
  }});
}
rows.sort((a, b) => b.json.engagement_score - a.json.engagement_score);
rows.forEach((r, i) => { r.json.rank = i + 1; });
return rows;
